// ==================== CCT SLA Helper Functions (Global) ====================
// Países da América do Sul para determinar VOO_CURTO
const PAISES_AMERICA_SUL = [
  'Brasil', 'Argentina', 'Chile', 'Uruguai', 'Paraguai', 
  'Bolívia', 'Peru', 'Equador', 'Colômbia', 'Venezuela',
  'Guiana', 'Suriname', 'Guiana Francesa'
];

// Determinar tipo de voo baseado no país de origem
function determinarTipoVoo(aeroportoOrigem: string, aeroportoPaisMap: Map<string, string>): 'VOO_CURTO' | 'VOO_LONGO' {
  const pais = aeroportoPaisMap.get(aeroportoOrigem?.toUpperCase()?.trim());
  return PAISES_AMERICA_SUL.includes(pais || '') ? 'VOO_CURTO' : 'VOO_LONGO';
}

// Calcular limite do SLA de manifestação baseado no tipo de voo
// SLA mede: tempo desde DEP até o prazo para manifestar no CCT
// Se já manifestou → SLA não se aplica (retorna null)
function calcularSlaLimite(
  tipoVoo: string,
  dataDecolagem: Date | null,
  eta: Date | null,
  statusCctOficial: string,
  dataManifestacao: Date | null
): Date | null {
  // Processos já entregues/finalizados → sem SLA
  const statusFinais = ['ENTREGUE', 'DLV', 'POD'];
  const statusNorm = (statusCctOficial || '').toUpperCase().trim();
  if (statusFinais.includes(statusNorm)) return null;

  // Já manifestado no CCT → still calculate the limit for reference (status will be CUMPRIDO)
  // Don't return null anymore so we can show "Cumprido" badge

  // Sem data de decolagem → não há como calcular SLA
  if (!dataDecolagem) return null;

  if (tipoVoo === 'VOO_CURTO') {
    return new Date(dataDecolagem.getTime() + 30 * 60 * 1000); // DEP + 30min
  }

  if (tipoVoo === 'VOO_LONGO') {
    if (eta) return new Date(eta.getTime() - 4 * 60 * 60 * 1000); // ETA - 4h
    return new Date(dataDecolagem.getTime() + 4 * 60 * 60 * 1000); // fallback: DEP + 4h
  }

  return null;
}

// Calcular status do SLA
function calcularSlaStatus(slaLimite: Date | null): 'OK' | 'ALERTA' | 'CRITICO' | 'VENCIDO' {
  if (!slaLimite) return 'OK';
  
  const now = new Date();
  const alertaLimite = new Date(slaLimite.getTime() - 60 * 60 * 1000); // -1 hora
  
  if (now >= slaLimite) return 'VENCIDO';
  if (now >= alertaLimite) return 'CRITICO';
  if (now >= new Date(slaLimite.getTime() - 2 * 60 * 60 * 1000)) return 'ALERTA';
  return 'OK';
}

const sleep = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

function isTransientMariaDbErrorMessage(message: string) {
  const normalized = message.toLowerCase();

  return normalized.includes('connection reset by peer') ||
    normalized.includes('connection read timed out') ||
    normalized.includes('read timed out') ||
    normalized.includes('timed out') ||
    normalized.includes('etimedout') ||
    normalized.includes('econnreset') ||
    normalized.includes('connection was forcibly closed') ||
    normalized.includes('max_user_connections') ||
    normalized.includes('ehostunreach') ||
    normalized.includes('econnrefused');
}

async function queryWithRetry<T>(
  operation: () => Promise<T>,
  options: { label: string; attempts?: number; baseDelayMs?: number; timeoutMs?: number }
): Promise<T> {
  const attempts = options.attempts ?? 3;
  const baseDelayMs = options.baseDelayMs ?? 500;
  const timeoutMs = options.timeoutMs ?? 8000;
  let lastError: unknown;

  for (let attempt = 1; attempt <= attempts; attempt++) {
    try {
      const result = await Promise.race([
        operation(),
        new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error('DB_TIMEOUT')), timeoutMs)
        ),
      ]);
      return result;
    } catch (error) {
      lastError = error;
      const errorMessage = error instanceof Error ? error.message : String(error);

      if (errorMessage === 'DB_TIMEOUT') {
        console.warn(`[${options.label}] query timed out after ${timeoutMs}ms on attempt ${attempt}/${attempts}`);
        if (attempt === attempts) throw new Error(`Query timed out after ${timeoutMs}ms`);
        await sleep(baseDelayMs * attempt);
        continue;
      }

      if (!isTransientMariaDbErrorMessage(errorMessage) || attempt === attempts) {
        throw error;
      }

      console.warn(`[${options.label}] transient MariaDB error on attempt ${attempt}/${attempts}: ${errorMessage}`);
      await sleep(baseDelayMs * attempt);
    }
  }

  throw lastError instanceof Error ? lastError : new Error(String(lastError));
}

function chunkArray<T>(items: T[], chunkSize: number): T[][] {
  if (items.length === 0) return [];

  const chunks: T[][] = [];
  for (let index = 0; index < items.length; index += chunkSize) {
    chunks.push(items.slice(index, index + chunkSize));
  }
  return chunks;
}

const VOUCHER_ETAPA_RANK: Record<string, number> = {
  A_PROCESSAR: 0, RASCUNHO: 1, OPERACAO: 2, AJUSTE_OPERACAO: 2,
  FISCAL: 3, AJUSTE_FISCAL: 3, SUPERVISOR: 4, FINANCEIRO: 5,
  ROBO: 6, CONCLUIDO: 7, CANCELADO: -1,
};

/**
 * Reconcilia duplicatas de t_vouchers para um mesmo numero_spo, mantendo o "vencedor":
 *   score = (n_anexos>0?100:0) + (linha_digitavel?50:0) + ETAPA_RANK
 * Empate: prefere `preferIfTie`; senão id lexicograficamente menor.
 * Apaga os perdedores em cascata (logs + anexos + voucher). Retorna o id vencedor.
 */
async function reconcileDuplicateVouchersBySpo(
  client: any,
  numeroSpo: string,
  preferIfTie: string | null
): Promise<string | null> {
  if (!numeroSpo) return null;
  const rows = await client.query(
    `SELECT v.id, v.etapa_atual, v.linha_digitavel, v.codigo_barras, v.created_at,
            (SELECT COUNT(*) FROM dados_dachser.t_voucher_anexos a WHERE a.voucher_id = v.id) AS n_anexos
     FROM dados_dachser.t_vouchers v
     WHERE v.numero_spo = ?`,
    [numeroSpo]
  );
  if (!rows || rows.length <= 1) return rows && rows[0] ? rows[0].id : null;

  const scored = rows.map((r: any) => ({
    id: String(r.id),
    score:
      ((Number(r.n_anexos) || 0) > 0 ? 100 : 0) +
      ((r.linha_digitavel || r.codigo_barras) ? 50 : 0) +
      (VOUCHER_ETAPA_RANK[r.etapa_atual] ?? 0),
  }));
  scored.sort((a: any, b: any) => {
    if (b.score !== a.score) return b.score - a.score;
    if (preferIfTie && a.id === preferIfTie) return -1;
    if (preferIfTie && b.id === preferIfTie) return 1;
    return a.id < b.id ? -1 : 1;
  });
  const winner = scored[0].id;
  const losers = scored.slice(1).map((s: any) => s.id);
  if (losers.length === 0) return winner;

  const placeholders = losers.map(() => '?').join(',');
  console.log(`Reconcile ${numeroSpo}: keeping ${winner}, deleting ${losers.length}:`, losers);
  try { await client.execute(`DELETE FROM dados_dachser.t_voucher_logs WHERE voucher_id IN (${placeholders})`, losers); } catch (e) { console.warn('del logs', e); }
  try { await client.execute(`DELETE FROM dados_dachser.t_voucher_anexos WHERE voucher_id IN (${placeholders})`, losers); } catch (e) { console.warn('del anexos', e); }
  try { await client.execute(`DELETE FROM dados_dachser.t_vouchers WHERE id IN (${placeholders})`, losers); } catch (e) { console.warn('del vouchers', e); }
  return winner;
}

