            evt.event_datetime || null,
            evt.location || null,
            evt.vessel_name || null,
            evt.voyage_number || null,
            evt.terminal || null,
            evt.source || 'JSONCARGO',
            evt.raw_data ? JSON.stringify(evt.raw_data) : null
